defmodule DevopsAutomation.CommandService do
  @moduledoc """
  Safe command execution service using an allowlist of permitted commands.
  Never passes raw user input to a shell.
  """

  # Allowlist of permitted commands with their allowed argument patterns
  @allowed_commands %{
    "disk_usage" => {"/usr/bin/df", ["-h"]},
    "list_containers" => {"/usr/bin/docker", ["ps", "--format", "table {{.Names}}\t{{.Status}}"]},
    "system_uptime" => {"/usr/bin/uptime", []},
    "memory_usage" => {"/usr/bin/free", ["-m"]},
    "list_services" => {"/usr/bin/systemctl", ["list-units", "--type=service", "--state=running"]},
    "check_port" => {"/usr/bin/ss", ["-tlnp"]},
    "ping" => :requires_validated_arg
  }

  @doc """
  Executes a pre-approved command by name.
  Returns {:ok, output} or {:error, reason}.
  """
  def execute(command_name, params \\ %{})

  def execute(command_name, params) when is_binary(command_name) do
    case Map.get(@allowed_commands, command_name) do
      nil ->
        {:error, :command_not_allowed}

      :requires_validated_arg ->
        execute_with_validated_args(command_name, params)

      {executable, args} ->
        run_command(executable, args)
    end
  end

  def execute(_, _), do: {:error, :invalid_input}

  defp execute_with_validated_args("ping", %{"host" => host}) do
    if valid_hostname?(host) do
      run_command("/usr/bin/ping", ["-c", "3", "-W", "5", host])
    else
      {:error, :invalid_argument}
    end
  end

  defp execute_with_validated_args(_, _), do: {:error, :missing_arguments}

  defp run_command(executable, args) do
    try do
      # Use System.cmd with the executable directly - NO shell interpolation
      case System.cmd(executable, args, stderr_to_stdout: true, timeout: 30_000) do
        {output, 0} ->
          {:ok, %{output: output, exit_code: 0}}

        {output, exit_code} ->
          {:error, %{output: output, exit_code: exit_code}}
      end
    rescue
      e in ErlangError ->
        {:error, %{reason: :execution_failed, message: Exception.message(e)}}
    catch
      :exit, {:timeout, _} ->
        {:error, :timeout}
    end
  end

  @doc """
  Validates that a string is a legitimate hostname/IP (no injection possible).
  """
  def valid_hostname?(host) when is_binary(host) do
    # Only allow alphanumeric, dots, hyphens - no shell metacharacters
    Regex.match?(~r/\A[a-zA-Z0-9][a-zA-Z0-9.\-]{0,253}[a-zA-Z0-9]\z/, host)
  end

  def valid_hostname?(_), do: false

  @doc """
