  end
end

defmodule DevopsAutomationWeb.CommandController do
  use DevopsAutomationWeb, :controller

  alias DevopsAutomation.CommandService

  def index(conn, _params) do
    json(conn, %{available_commands: CommandService.available_commands()})
  end

  def execute(conn, %{"command" => command_name} = params) do
    case CommandService.execute(command_name, params) do
      {:ok, result} ->
        json(conn, %{status: "success", data: result})

      {:error, :command_not_allowed} ->
        conn
        |> put_status(:forbidden)
        |> json(%{
          status: "error",
          message: "Command not in allowlist",
          available_commands: CommandService.available_commands()
        })

      {:error, :invalid_argument} ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: "Invalid argument provided"})

      {:error, :timeout} ->
        conn
        |> put_status(:gateway_timeout)
        |> json(%{status: "error", message: "Command timed out"})

      {:error, %{output: output, exit_code: code}} ->
        conn
        |> put_status(:unprocessable_entity)
        |> json(%{status: "error", exit_code: code, output: output})

      {:error, reason} ->
        conn
        |> put_status(:internal_server_error)
        |> json(%{status: "error", message: inspect(reason)})
    end
  end

  def execute(conn, _params) do
    conn
    |> put_status(:bad_request)
    |> json(%{status: "error", message: "Missing 'command' parameter"})
  end
end